import React, { useState } from "react";
import { Link } from "react-router-dom";
import "./Home.css";

const heroImage =
  "https://images.pexels.com/photos/1643383/pexels-photo-1643383.jpeg";

const listingsData = [
  {
    id: 1,
    name: "Luxury Beach Villa",
    location: "Goa",
    price: 12500,
    rating: 4.8,
    image:
      "https://images.pexels.com/photos/2102587/pexels-photo-2102587.jpeg",
    description: "Experience ocean views and sunsets in this luxury stay.",
  },
  {
    id: 2,
    name: "Cozy Mountain Cabin",
    location: "Manali",
    price: 8500,
    rating: 4.6,
    image:
      "https://images.pexels.com/photos/277572/pexels-photo-277572.jpeg",
    description: "Peaceful retreat surrounded by snow and pine trees.",
  },
  {
    id: 3,
    name: "Modern City Apartment",
    location: "Mumbai",
    price: 9500,
    rating: 4.7,
    image:
      "https://images.pexels.com/photos/271624/pexels-photo-271624.jpeg",
    description: "Stay close to the city center with all modern amenities.",
  },
  {
    id: 4,
    name: "Traditional Heritage Home",
    location: "Jaipur",
    price: 7800,
    rating: 4.9,
    image:
      "https://images.pexels.com/photos/259588/pexels-photo-259588.jpeg",
    description: "Enjoy a royal experience with cultural interiors.",
  },
];

export default function Home() {
  const [filters, setFilters] = useState({
    location: "",
    checkIn: "",
    checkOut: "",
    guests: "",
  });

  // Filter logic (by location only for simplicity)
  const filteredListings = listingsData.filter((home) =>
    home.location.toLowerCase().includes(filters.location.toLowerCase())
  );

  const handleChange = (e) => {
    setFilters({ ...filters, [e.target.name]: e.target.value });
  };

  return (
    <div className="home-container">
      {/* Hero Section */}
      <section
        className="hero-section"
        style={{ backgroundImage: `url(${heroImage})` }}
      >
        <div className="hero-overlay">
          <h1 className="hero-title">Find Your Perfect Stay</h1>
          <p className="hero-subtitle">
            Discover homes, villas, and experiences you’ll love — just like Airbnb.
          </p>

          {/* Enhanced Search Bar */}
          <div className="search-bar-advanced">
            <div className="search-item">
              <label>Where</label>
              <input
                type="text"
                name="location"
                placeholder="Search destination..."
                value={filters.location}
                onChange={handleChange}
              />
            </div>

            <div className="search-item">
              <label>Check-In</label>
              <input
                type="date"
                name="checkIn"
                value={filters.checkIn}
                onChange={handleChange}
              />
            </div>

            <div className="search-item">
              <label>Check-Out</label>
              <input
                type="date"
                name="checkOut"
                value={filters.checkOut}
                onChange={handleChange}
              />
            </div>

            <div className="search-item">
              <label>Guests</label>
              <input
                type="number"
                name="guests"
                placeholder="Add guests"
                min="1"
                value={filters.guests}
                onChange={handleChange}
              />
            </div>

            <button className="search-btn">🔍 Search</button>
          </div>
        </div>
      </section>

      {/* Listings Section */}
      <section className="listing-section">
        <h2 className="section-title">Available Stays</h2>
        <div className="listing-grid">
          {filteredListings.length > 0 ? (
            filteredListings.map((home) => (
              <div key={home.id} className="listing-card">
                <img src={home.image} alt={home.name} />
                <div className="listing-content">
                  <h3>{home.name}</h3>
                  <p className="location">📍 {home.location}</p>
                  <p className="description">{home.description}</p>

                  <div className="price-rating">
                    <span className="price">
                      ₹{home.price.toLocaleString()} / night
                    </span>
                    <span className="rating">⭐ {home.rating}</span>
                  </div>

                  <Link to={`/booking/${home.id}`}>
                    <button className="explore-btn">Book Now</button>
                  </Link>
                </div>
              </div>
            ))
          ) : (
            <p className="no-results">No stays found. Try another location!</p>
          )}
        </div>
      </section>
    </div>
  );
}
